mapper.select:
SELECT S1.VNENTRLON_ID /*식별번호*/ , S1.RCMD_ENPR_BZN /*사업자번호*/ , S1.ETNM /*기업명*/ , S1.RGSN_TS /*등록일*/ , S1.RECOMEND_STTUS /*추천상태*/ , (SELECT COM_CD_NM FROM IVBADM.TB_BOX_IVT_COM_CD_D WHERE GRP_CD_ID = 'RST01' AND COM_CD_ID = S1.RECOMEND_STTUS) AS RECOMEND_STTUS_NM /*추천상태명*/ , S1.INVT_INSTT_DLIV_MSG /*투자기관에전달할 메시지*/ FROM TB_BOX_IVT_VNENTRLON_REQST_BASS_M S1 WHERE 1=1
AND S1.UTLINSTT_ID = #{searchUtlinsttId}
ORDER BY S1.RGSN_TS DESC

SELECT S1.VNENTRLON_ID /*식별번호*/ , S1.BZN /*사업자번호*/ , S1.UTLINSTT_ID /*이용기관 ID*/ , S1.ETNM /*기업명*/ , S1.RGSN_TS /*등록일*/ , S1.RECOMEND_STTUS_CM /*추천상태*/ , S1.RECOMEND_STTUS_CM_RM /*상태가 비고일 때 관리자가 작성한 메세지*/ , (SELECT A.ETNM FROM IVBADM.TB_BOX_IVT_ENPR_INFO_M A WHERE A.UTLINSTT_ID = S1.UTLINSTT_ID) AS INVM_ENPR_NM /*추천기관명*/ , (SELECT COM_CD_NM FROM IVBADM.TB_BOX_IVT_COM_CD_D WHERE GRP_CD_ID = 'RST02' AND COM_CD_ID = S1.RECOMEND_STTUS_CM) AS RECOMEND_STTUS_CM_NM /*추천상태명*/ FROM TB_BOX_IVT_VNENT_RLON_APLC_RGSN_M S1 WHERE 1=1
AND S1.BZN = #{searchRcmdEnrpBzn}
ORDER BY S1.RGSN_TS DESC

SELECT MAX(INVM_ENPR_NM) AS INVM_ENPR_NM
FROM TB_BOX_IVT_AGREM_VNENTR_INVT_MANAGE_M
WHERE BZN=#{bzn}

mapper.insert:
INSERT INTO TB_BOX_IVT_VNENTRLON_REQST_BASS_M(
    VNENTRLON_ID	            , /* 	식별번호	 */
    RCMD_ENPR_BZN	            , /* 	제안 기업 사업자번호	 */
    UTLINSTT_ID	                , /* 	이용기관(회사) ID	 */
    ETNM	                    , /* 	기업명	 */
    RPRNM	                    , /* 	대표자명	 */
    COL	                        , /* 	설립년월일	 */
    ADR	                        , /* 	본사 주소	 */
    BTNM	                    , /* 	업종명(표준산업분류)	 */
    INVT_INDUTY_SE	            , /* 	투자업종 구분	 */
    MAIN_PRODUCT	            , /* 	주요제품	 */
    RSPR_NM	                    , /* 	기업 담당자명	 */
    RSPR_JBCL_NM	            , /* 	담당자 직책	 */
    RSPR_CNPL_TPN	            , /* 	담당자 연락처	 */
    RSPR_EAD	                , /* 	담당자 이메일	 */
    ENTRPRS_CMPTPW	            , /* 	기업 경쟁력 또는성장가능성	 */
    FLLWINVT_POSBLTY_EXPECT_ERA	, /* 	후속투자 가능성 및예상시기	 */
    INVT_DTLS_INVT_INSTT	    , /* 	투자내역_투자기관	 */
    INVT_DTLS_INVT_PNTTM	    , /* 	투자내역_투자라운드(직전)	 */
    INVT_DTLS_INVT_AMOUNT	    , /* 	투자내역_투자금액(원)	 */
    INVT_DTLS_INVT_DE	        , /* 	투자내역_투자일자(직전)	 */
    INVT_DTLS_STKPC	            , /* 	투자내역_주당가격(원)	 */
    INVT_DTLS_ETVL_AMT	        , /* 	투자내역_기업가치(원)	 */
    INVT_DTLS_INVT_KND	        , /* 	투자내역_투자종류	 */
    INVT_DTLS_RM	            , /* 	투자내역_비고	 */
    CHRG_AUDOFIR_RSPR_NM	    , /* 	담당심사역_담당자이름	 */
    CHRG_AUDOFIR_RSPR_JBCL_NM	, /* 	담당심사역_담당자직책	 */
    CHRG_AUDOFIR_RSPR_CNPL_TPN	, /* 	담당심사역_담당자연락처 	 */
    CHRG_AUDOFIR_RSPR_EAD	    , /* 	담당심사역_담당자이메일 	 */
    CONTACT_AUDOFIR_RSPR_NM	    , /* 	연락담당자_담당자이름	 */
    CONTACT_AUDOFIR_RSPR_JBCL_NM	, /* 	연락담당자_담당자직책	 */
    CONTACT_AUDOFIR_RSPR_CNPL_TPN	, /* 	연락담당자_담당자연락처 	 */
    CONTACT_AUDOFIR_RSPR_EAD	    , /* 	연락담당자_담당자이메일 	 */
    
    RECOMEND_IBK_BUZPLC	        , /* 	추천 기업은행 영업점	 */
    
    RECOMEND_STTUS	            , /* 	추천 진행 상태	 */
     RGSN_TS	                    , /* 	등록일	 */
    RGSN_USER_ID	            , /* 	동록자 ID	 */
    AMNN_TS	                    , /* 	수정일	 */
    AMNN_USER_ID	              /* 	수정자 ID	 */
) VALUES(
     #{vnentrlonId}
    ,#{rcmdEnprBzn}
    ,#{utlinsttId}
    ,#{etnm}
    ,#{rprnm}
    ,#{col}
    ,#{adr}
    ,#{btnm}
    ,#{invtIndutySe}
    ,#{mainProduct}
    ,#{rsprNm}
    ,#{rsprJbclNm}
    ,#{rsprCnplTpn}
    ,#{rsprEad}
    ,#{entrprsCmptpw}
    ,#{fllwinvtPosbltyExpectEra}
    ,#{invtDtlsInvtInstt}
    ,#{invtDtlsInvtPnttm}
    ,#{invtDtlsInvtAmount}
    ,#{invtDtlsInvtDe}
    ,#{invtDtlsStkpc}
    ,#{invtDtlsEtvlAmt}
    ,#{invtDtlsInvtKnd}
    ,#{invtDtlsRm}
    ,#{chrgAudofirRsprNm}
    ,#{chrgAudofirRsprJbclNm}
    ,#{chrgAudofirRsprCnplTpn}
    ,#{chrgAudofirRsprEad}
    ,#{contactAudofirRsprNm}
    ,#{contactAudofirRsprJbclNm}
    ,#{contactAudofirRsprCnplTpn}
    ,#{contactAudofirRsprEad}
    
    ,#{recomendIbkBuzplc}
    
    ,#{recomendSttus}
    ,SYSDATE
    ,#{utlinsttId}
    ,SYSDATE
    ,#{utlinsttId}
)

INSERT INTO TB_BOX_IVT_VNENT_RLON_APLC_RGSN_M(
    VNENTRLON_ID,	            /*벤처대출 ID 	 */
    UTLINSTT_ID,	            /*이용기관(회사) ID 	 */
    ETNM,	            /*기업명 	 */
    RPRNM,	            /*대표자명 	 */
    BZN,	            /*사업자번호 	 */
    COL,	            /*설립년월일 	 */
    ADR,	            /*본사 주소 	 */
    RSPR_NM,	            /*기업 담당자명 	 */
    RSPR_JBCL_NM,	            /*담당자 직책 	 */
    RSPR_CNPL_TPN,	            /*담당자 연락처 	 */
    RSPR_EAD,	            /*담당자 이메일 	 */
    RECOMEND_STTUS_CM,	            /*진행상태코드	 */
    RGSN_TS,	            /*등록일 	 */
    RGSN_USER_ID,	            /*동록자 ID 	 */
    AMNN_TS,	            /*수정일 	 */
    AMNN_USER_ID	            /*수정자 ID 	 */
) VALUES(
     #{vnentrlonId}
    ,#{utlinsttId}
    ,#{etnm}
    ,#{rprnm}
    ,#{bzn}
    ,#{col}
    ,#{adr}
    ,#{rsprNm}
    ,#{rsprJbclNm}
    ,#{rsprCnplTpn}
    ,#{rsprEad}
    ,#{recomendSttusCm}
    ,SYSDATE
    ,#{utlinsttId}
    ,SYSDATE
    ,#{utlinsttId}
)

mapper.update:
UPDATE TB_BOX_IVT_VNENT_RLON_APLC_RGSN_M
SET
    VNENTRLON_ID = #{vnentrlonId}
    , UTLINSTT_ID = #{utlinsttId}
    , BIZRNO = #{bizrno}
    , VAT_STDTAX_PROOF = #{vatStdtaxProof}
    , CPR_RGIST_MATTER_ALL_CRTF = #{cprRgistMatterAllCrtf}
    , STCH_INFO_MNGM_NO = #{stchInfoMngmNo}
    , CMPNY_INTRCN = #{cmpnyIntrcn}
    , ETNM = #{etnm}
    , RPRNM = #{rprnm}
    , BZN = #{bzn}
    , COL = #{col}
    , ADR = #{adr}
    , RSPR_NM = #{rsprNm}
    , RSPR_JBCL_NM = #{rsprJbclNm}
    , RSPR_CNPL_TPN = #{rsprCnplTpn}
    , RSPR_EAD = #{rsprEad}
    , INNF_INQ_COSN = #{innfInqCosn}
    , INNF_CLUS_COSN = #{innfClusCosn}
    , ATCSC_ATCHMNFL = #{atcscAtchmnfl}
    , GMTSCK_ANACT = #{gmtsckAnact}
    , INVT_CNFRMN = #{invtCnfrmn}
    , CPTAL_USGPLN = #{cptalUsgpln}
    , SPRN_APFR = #{sprnApfr}
    , RECOMEND_STTUS_CM = #{recomendSttusCm}
    , AMNN_TS = CURRENT_TIMESTAMP
    , AMNN_USER_ID = #{utlinsttId}
WHERE 1=1
AND VNENTRLON_ID = #{vnentrlonId}

