INSERT INTO TB_BOX_IVT_IDIV_ATCH_R
(
    INVT_ID
    , ATCH_DSNC
    , FILE_ID
    , BSDS_CD
    , RGSN_USER_ID
    , RGSN_TS
    , AMNN_USER_ID
    , AMNN_TS
     
)
VALUES
(
    #{invtId}
    , #{atchDsnc}
    , #{fileId}
    , #{bsdsCd}
    , #{rgsnUserId}
    , CURRENT_TIMESTAMP
    , #{rgsnUserId}
    , CURRENT_TIMESTAMP
)
